      {/* --- CONTENT: PDF --- */}
      {activeTab === 'pdf' && (
        <div className="space-y-6">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-semibold text-slate-800">Ressources Documentaires</h3>
