import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { ModuleView } from './components/ModuleView';
import { ContactModal } from './components/ContactModal';
import { NotificationBanner } from './components/NotificationBanner';
import { NotificationManagerModal } from './components/NotificationManagerModal';
import { INITIAL_DATA } from './constants';
import { Year, Semester, Module, AppNotification, DataStore } from './types';
import { Folder, FolderOpen, Book, ChevronRight, Loader2 } from 'lucide-react';

export default function App() {
  const [data, setData] = useState<DataStore>(INITIAL_DATA);
  const [loading, setLoading] = useState(true);
  const [selectedYear, setSelectedYear] = useState<Year | null>(null);
  const [selectedSemester, setSelectedSemester] = useState<Semester | null>(null);
  const [selectedModule, setSelectedModule] = useState<Module | null>(null);

  // Modals state
  const [isContactOpen, setIsContactOpen] = useState(false);
  const [isNotifManagerOpen, setIsNotifManagerOpen] = useState(false);

  // Charger les données depuis le fichier JSON au démarrage
  useEffect(() => {
    const loadData = async () => {
      try {
        // On ajoute un timestamp pour éviter que le navigateur ne garde le fichier en cache
        const response = await fetch(`${import.meta.env.BASE_URL}data.json?t=${Date.now()}`);
        if (response.ok) {
          const jsonData = await response.json();
          setData(jsonData);
        } else {
          console.warn("Impossible de charger data.json, utilisation des données par défaut.");
        }
      } catch (e) {
        console.error("Erreur chargement données:", e);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  const handleUpdateModule = (updatedModule: Module) => {
    // Deep update of state structure
    if (!selectedYear || !selectedSemester) return;

    const newData = { ...data };
    const yearIndex = newData.years.findIndex(y => y.id === selectedYear.id);
    if (yearIndex === -1) return;

    const semIndex = newData.years[yearIndex].semesters.findIndex(s => s.id === selectedSemester.id);
    if (semIndex === -1) return;

    const modIndex = newData.years[yearIndex].semesters[semIndex].modules.findIndex(m => m.id === updatedModule.id);
    if (modIndex === -1) return;

    newData.years[yearIndex].semesters[semIndex].modules[modIndex] = updatedModule;

    setData(newData);
    setSelectedModule(updatedModule); // Update local view state
  };

  // Notification Management
  const handleAddNotification = (newNotif: AppNotification) => {
      setData(prev => ({
          ...prev,
          notifications: [newNotif, ...prev.notifications]
      }));
  };

  const handleDeleteNotification = (id: string) => {
      setData(prev => ({
          ...prev,
          notifications: prev.notifications.filter(n => n.id !== id)
      }));
  };

  // Fonction pour télécharger la configuration actuelle en JSON
  const handleExportData = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(data, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "data.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
    alert("Fichier 'data.json' téléchargé !\n\nPour mettre à jour le site pour tout le monde :\n1. Remplacez le fichier 'public/data.json' dans votre code par celui-ci.\n2. Envoyez les modifications sur GitHub.");
  };

  const resetSelection = () => {
    setSelectedYear(null);
    setSelectedSemester(null);
    setSelectedModule(null);
  };

  const renderDashboard = () => (
    <div className="max-w-5xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="mb-8 text-center md:text-left">
        <h1 className="text-3xl font-bold text-slate-900 mb-2">Bienvenue sur <span className="text-primary-600">MedQCM Pro</span></h1>
        <p className="text-slate-600 max-w-2xl">Sélectionnez votre année d'étude pour accéder aux modules, QCMs et ressources PDF.</p>
      </div>

      {/* Notifications Area */}
      <NotificationBanner notifications={data.notifications} />

      {loading ? (
        <div className="flex justify-center items-center py-20">
          <Loader2 className="w-10 h-10 text-primary-600 animate-spin" />
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-6">
          {data.years.map((year) => (
            <div key={year.id} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
              <div 
                className="p-4 bg-slate-50 border-b border-slate-100 flex items-center gap-3 cursor-pointer hover:bg-slate-100 transition-colors"
                onClick={() => setSelectedYear(selectedYear?.id === year.id ? null : year)}
              >
                {selectedYear?.id === year.id ? <FolderOpen className="text-primary-600 w-6 h-6" /> : <Folder className="text-slate-400 w-6 h-6" />}
                <h2 className="text-lg font-semibold text-slate-800">{year.name}</h2>
                <ChevronRight className={`ml-auto w-5 h-5 text-slate-400 transition-transform ${selectedYear?.id === year.id ? 'rotate-90' : ''}`} />
              </div>

              {selectedYear?.id === year.id && (
                <div className="p-4 bg-white animate-in slide-in-from-top-2">
                   <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                      {year.semesters.map(semester => (
                          <div key={semester.id} className="border border-slate-200 rounded-lg p-4 hover:border-primary-300 transition-colors">
                             <h3 className="font-medium text-slate-700 mb-3 border-b border-slate-100 pb-2">{semester.name}</h3>
                             <ul className="space-y-2">
                               {semester.modules.length > 0 ? (
                                 semester.modules.map(module => (
                                   <li key={module.id}>
                                     <button 
                                       onClick={() => {
                                          setSelectedSemester(semester);
                                          setSelectedModule(module);
                                       }}
                                       className="flex items-center gap-2 text-sm text-slate-600 hover:text-primary-600 w-full text-left p-2 rounded hover:bg-slate-50 transition-all group"
                                     >
                                       <div className="bg-slate-100 p-1.5 rounded text-slate-400 group-hover:text-primary-500 group-hover:bg-primary-50 transition-colors">
                                          <Book className="w-4 h-4" />
                                       </div>
                                       {module.name}
                                     </button>
                                   </li>
                                 ))
                               ) : (
                                 <li className="text-xs text-slate-400 italic p-2">Aucun module disponible.</li>
                               )}
                             </ul>
                          </div>
                      ))}
                   </div>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );

  return (
    <Layout 
      onNavigateHome={resetSelection}
      onContactClick={() => setIsContactOpen(true)}
      onManageNotifications={() => setIsNotifManagerOpen(true)}
    >
      {selectedModule ? (
        <ModuleView 
          moduleData={selectedModule} 
          onBack={() => setSelectedModule(null)}
          onUpdateModule={handleUpdateModule}
        />
      ) : (
        renderDashboard()
      )}

      <ContactModal isOpen={isContactOpen} onClose={() => setIsContactOpen(false)} />

      <NotificationManagerModal 
          isOpen={isNotifManagerOpen} 
          onClose={() => setIsNotifManagerOpen(false)}
          notifications={data.notifications}
          onAdd={handleAddNotification}
          onDelete={handleDeleteNotification}
          onExport={handleExportData}
      />
    </Layout>
  );
}

import React, { useState } from 'react';
import { X, Plus, Trash2, Bell, Download, Save } from 'lucide-react';
import { AppNotification } from '../types';

interface NotificationManagerModalProps {
  isOpen: boolean;
  onClose: () => void;
  notifications: AppNotification[];
  onAdd: (notif: AppNotification) => void;
  onDelete: (id: string) => void;
  onExport: () => void;
}

export const NotificationManagerModal: React.FC<NotificationManagerModalProps> = ({ 
  isOpen, onClose, notifications, onAdd, onDelete, onExport
}) => {
  const [message, setMessage] = useState('');
  const [type, setType] = useState<'info' | 'warning' | 'urgent'>('info');

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!message.trim()) return;

    const newNotif: AppNotification = {
      id: `notif-${Date.now()}`,
      message: message,
      type: type,
      date: new Date().toLocaleDateString('fr-FR')
    };

    onAdd(newNotif);
    setMessage('');
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden relative flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="p-6 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
            <div className="flex items-center gap-3">
                <div className="bg-white p-2 rounded-lg shadow-sm">
                    <Bell className="w-5 h-5 text-primary-600" />
                </div>
                <div>
                    <h2 className="text-xl font-bold text-slate-800">Gestion des Annonces</h2>
                    <p className="text-xs text-slate-500">Ajoutez des messages visibles sur l'accueil</p>
                </div>
            </div>
            <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
                <X className="w-5 h-5" />
            </button>
        </div>

        {/* Content */}
        <div className="p-6 overflow-y-auto flex-1">

            {/* Admin Export Section - NEW */}
            <div className="mb-6 bg-indigo-50 border border-indigo-100 p-4 rounded-xl">
                 <h3 className="text-sm font-bold text-indigo-900 mb-2 flex items-center gap-2">
                     <Save className="w-4 h-4" /> Sauvegarder les modifications
                 </h3>
                 <p className="text-xs text-indigo-700 mb-3 leading-relaxed">
                     Les changements faits ici (et les nouvelles questions) sont temporaires. 
                     Pour mettre à jour le site <strong>pour tout le monde</strong> sans changer le lien :
                 </p>
                 <button 
                    onClick={onExport}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-2 rounded-lg text-sm font-medium transition-colors shadow-sm"
                 >
                     <Download className="w-4 h-4" /> Télécharger data.json
                 </button>
                 <p className="text-[10px] text-indigo-500 mt-2 text-center">
                     Remplacez ensuite le fichier <code>public/data.json</code> dans votre code par ce fichier téléchargé.
                 </p>
            </div>

            <hr className="border-slate-100 mb-6" />

            {/* Add Form */}
            <form onSubmit={handleSubmit} className="mb-8 bg-slate-50 p-4 rounded-xl border border-slate-200">
                <h3 className="text-sm font-semibold text-slate-700 mb-3 flex items-center gap-2">
                    <Plus className="w-4 h-4" /> Nouvelle Annonce
                </h3>
                <div className="space-y-3">
                    <div>
                        <label className="block text-xs font-medium text-slate-500 mb-1">Type de message</label>
                        <div className="flex gap-2">
                            <button 
                                type="button"
                                onClick={() => setType('info')}
                                className={`flex-1 py-2 text-xs font-medium rounded-lg border ${type === 'info' ? 'bg-blue-50 border-blue-200 text-blue-700 ring-1 ring-blue-500/20' : 'bg-white border-slate-200 text-slate-600'}`}
                            >
                                Info
                            </button>
                            <button 
                                type="button"
                                onClick={() => setType('warning')}
                                className={`flex-1 py-2 text-xs font-medium rounded-lg border ${type === 'warning' ? 'bg-amber-50 border-amber-200 text-amber-700 ring-1 ring-amber-500/20' : 'bg-white border-slate-200 text-slate-600'}`}
                            >
                                Attention
                            </button>
                            <button 
                                type="button"
                                onClick={() => setType('urgent')}
                                className={`flex-1 py-2 text-xs font-medium rounded-lg border ${type === 'urgent' ? 'bg-red-50 border-red-200 text-red-700 ring-1 ring-red-500/20' : 'bg-white border-slate-200 text-slate-600'}`}
                            >
                                Urgent
                            </button>
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs font-medium text-slate-500 mb-1">Message</label>
                        <textarea 
                            value={message}
                            onChange={e => setMessage(e.target.value)}
                            placeholder="Votre annonce ici..."
                            className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-primary-500 outline-none"
                            rows={3}
                        />
                    </div>
                    <button 
                        type="submit"
                        disabled={!message.trim()}
                        className="w-full bg-primary-600 text-white py-2 rounded-lg text-sm font-medium hover:bg-primary-700 disabled:opacity-50 transition-colors"
                    >
                        Publier l'annonce
                    </button>
                </div>
            </form>

            {/* List */}
            <div>
                <h3 className="text-sm font-semibold text-slate-700 mb-3">Annonces Actives ({notifications.length})</h3>
                <div className="space-y-2">
                    {notifications.length === 0 ? (
                        <p className="text-sm text-slate-400 italic text-center py-4">Aucune annonce active.</p>
                    ) : (
                        notifications.map(notif => (
                            <div key={notif.id} className="flex items-center gap-3 p-3 bg-white border border-slate-100 rounded-lg shadow-sm group">
                                <div className={`w-2 h-2 rounded-full shrink-0 ${
                                    notif.type === 'urgent' ? 'bg-red-500' : 
                                    notif.type === 'warning' ? 'bg-amber-500' : 'bg-blue-500'
                                }`} />
                                <div className="flex-1 min-w-0">
                                    <p className="text-sm text-slate-800 line-clamp-2">{notif.message}</p>
                                    <p className="text-xs text-slate-400">{notif.date}</p>
                                </div>
                                <button 
                                    onClick={() => onDelete(notif.id)}
                                    className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                    title="Supprimer"
                                >
                                    <Trash2 className="w-4 h-4" />
                                </button>
                            </div>
                        ))
                    )}
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

